vector<int> beautifulIndices(string s, string a, string b, int k) {
    vector<int> res;
    for (int i = 0; i <= s.length() - a.length(); i++) {
        if (s.substr(i, a.length()) == a) {
            bool found = false;
            for (int j = 0; j <= s.length() - b.length(); j++) {
                if (s.substr(j, b.length()) == b && abs(j - i) <= k) {
                    found = true;
                    break;
                }
            }
            if (found) {
                res.push_back(i);
            }
        }
    }
    return res;
}
